let lunches = []; // состояние (mini database)

function addLunchToEnd(lunches, menuItem) {
  lunches.push(menuItem);
  console.log(`${menuItem} added to the end of the lunch menu.`);
  return lunches;
}

function addLunchToStart(lunches, menuItem) {
  lunches.unshift(menuItem);
  console.log(`${menuItem} added to the start of the lunch menu.`);
  return lunches;
}

function removeLastLunch(lunches) {
  let removedItem = lunches.pop();
  if (removedItem === undefined) {
    console.log('No lunches to remove.');
  } else {
    console.log(`${removedItem} removed from the end of the lunch menu.`);
  }
  return lunches;
}

function removeFirstLunch(lunches) {
  let removedItem = lunches.shift();
  if (removedItem === undefined) {
    console.log('No lunches to remove.');
  } else {
    console.log(`${removedItem} removed from the start of the lunch menu.`);
  }
  return lunches;
}

function getRandomLunch(lunches) {
  let randomIndex = Math.floor(Math.random() * lunches.length);
  let randomItem = lunches[randomIndex];
  if (randomItem === undefined) {
    console.log('No lunches available.');
  } else {
    console.log(`Randomly selected lunch: ${randomItem}`);
  }
}

function showLunchMenu(lunches) {
  if (lunches.length > 0) {
    console.log(`Menu items: ${lunches.join(', ')}`);
  } else {
    console.log('The menu is empty.');
  }
}
